// Auto-generated by scripts/build.mjs — live white-hat industry RSS at /feed.xml
const SOURCES = ["https://news.google.com/rss/search?q=AEO+GEO+SEO+generative+engine+optimization+when:3d&hl=en-US&gl=US&ceid=US:en","https://news.google.com/rss/search?q=adtech+programmatic+advertising+when:3d&hl=en-US&gl=US&ceid=US:en"];
const SITE_URL = "https://chatad-land-ekx.pages.dev";
const SITE_NAME = "ChatAd Land";
const FEED_DESC = "White-hat industry headlines in SEO, GEO, AEO, and AdTech. Each item links to the original publisher; ChatAd Land does not republish third-party full text.";

function decodeXml(text) {
  return String(text)
    .replace(/&lt;/g, '<')
    .replace(/&gt;/g, '>')
    .replace(/&amp;/g, '&')
    .replace(/&apos;/g, "'")
    .replace(/&quot;/g, '"');
}

function escapeXml(s) {
  return String(s).replace(/[<>&'"]/g, function(c) {
    return ({ '<': '&lt;', '>': '&gt;', '&': '&amp;', "'": '&apos;', '"': '&quot;' })[c];
  });
}

function extractItems(xml, max) {
  const items = [];
  const itemRe = /<item[\s\S]*?<\/item>/g;
  const titleRe = /<title>([\s\S]*?)<\/title>/;
  const linkRe = /<link>([\s\S]*?)<\/link>/;
  const pubDateRe = /<pubDate>([\s\S]*?)<\/pubDate>/;
  const descRe = /<description>([\s\S]*?)<\/description>/;
  const sourceRe = /<source[^>]*>([\s\S]*?)<\/source>/;
  let m;
  while ((m = itemRe.exec(xml)) && items.length < max) {
    const block = m[0];
    const t = titleRe.exec(block);
    const l = linkRe.exec(block);
    if (!t || !l) continue;
    const title = decodeXml(t[1].replace('<![CDATA[', '').replace(']]>', '').trim());
    const link = decodeXml(l[1].replace('<![CDATA[', '').replace(']]>', '').trim());
    if (!title || !link) continue;
    const pub = pubDateRe.exec(block);
    const desc = descRe.exec(block);
    const src = sourceRe.exec(block);
    items.push({
      title,
      link,
      pubDate: pub ? pub[1].trim() : new Date().toUTCString(),
      description: desc
        ? decodeXml(desc[1].replace('<![CDATA[', '').replace(']]>', '').trim()).slice(0, 280)
        : 'Third-party headline linked for white-hat context. Read the original source.',
      source: src ? decodeXml(src[1].trim()) : 'Industry'
    });
  }
  return items;
}

function renderRss(items) {
  const now = new Date().toUTCString();
  const rows = items.map(function(it) {
    return [
      '  <item>',
      '    <title>' + escapeXml(it.title) + '</title>',
      '    <link>' + escapeXml(it.link) + '</link>',
      '    <guid isPermaLink="true">' + escapeXml(it.link) + '</guid>',
      '    <pubDate>' + escapeXml(it.pubDate) + '</pubDate>',
      '    <category>White hat context</category>',
      '    <description>' + escapeXml(it.description) + '</description>',
      '    <source url="' + escapeXml(it.link) + '">' + escapeXml(it.source) + '</source>',
      '  </item>'
    ].join('\n');
  }).join('\n');

  return [
    '<?xml version="1.0" encoding="UTF-8"?>',
    '<rss version="2.0" xmlns:atom="http://www.w3.org/2005/Atom">',
    '<channel>',
    '  <title>' + escapeXml(SITE_NAME + ' | White Hat GEO/SEO/AEO Context') + '</title>',
    '  <link>' + escapeXml(SITE_URL + '/industry-feed/') + '</link>',
    '  <description>' + escapeXml(FEED_DESC) + '</description>',
    '  <language>en-us</language>',
    '  <lastBuildDate>' + now + '</lastBuildDate>',
    '  <generator>ChatAd Land context feed</generator>',
    '  <atom:link href="' + escapeXml(SITE_URL + '/feed.xml') + '" rel="self" type="application/rss+xml"/>',
    rows,
    '</channel>',
    '</rss>'
  ].join('\n');
}

export async function onRequestGet() {
  try {
    const results = [];
    for (const src of SOURCES) {
      const res = await fetch(src, { headers: { 'User-Agent': 'Mozilla/5.0 (compatible; ChatAdLand-context/1.0)' } });
      if (!res.ok) continue;
      const xml = await res.text();
      results.push(...extractItems(xml, 8));
      if (results.length >= 12) break;
    }
    const body = renderRss(results.slice(0, 12));
    return new Response(body, {
      headers: {
        'content-type': 'application/rss+xml; charset=utf-8',
        'cache-control': 'public, max-age=900'
      }
    });
  } catch (e) {
    const body = renderRss([]);
    return new Response(body, {
      headers: {
        'content-type': 'application/rss+xml; charset=utf-8',
        'cache-control': 'public, max-age=300'
      }
    });
  }
}
